export const getTransfer = async (id: number, options?: RequestInit): Promise<Transfer> => {

  return customFetch<Transfer>(getGetTransferUrl(id),
  {
    ...options,
    method: 'GET'


  }
);}





export const getGetTransferQueryKey = (id: number,) => {
    return [
    `/api/transfers/${id}`
    ] as const;
    }


export const getGetTransferQueryOptions = <TData = Awaited<ReturnType<typeof getTransfer>>, TError = ErrorType<void>>(id: number, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getTransfer>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getGetTransferQueryKey(id);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof getTransfer>>> = ({ signal }) => getTransfer(id, { signal, ...requestOptions });





   return  { queryKey, queryFn, enabled: id !== null && id !== undefined, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof getTransfer>>, TError, TData> & { queryKey: QueryKey }
}

export type GetTransferQueryResult = NonNullable<Awaited<ReturnType<typeof getTransfer>>>
export type GetTransferQueryError = ErrorType<void>


/**
 * @summary Get a single transfer
 */

export function useGetTransfer<TData = Awaited<ReturnType<typeof getTransfer>>, TError = ErrorType<void>>(
 id: number, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getTransfer>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getGetTransferQueryOptions(id,options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return withQueryKey(query, queryOptions.queryKey);
}







